var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>그라운드 원</color>\\n제3 선착장 코핀 컴퍼니 임시 본사","JPN":"管理局直轄都市<color=#ffd34c>グラウンド・ワン</color>\\n第3船着き場コフィンカンパニー臨時本社","ENG":"[[","TWN":"管理局直轄城市<color=#ffd34c>G1</color>\\n第3碼頭科芬公司臨時總部","SCN":"管理局直辖城市<color=#ffd34c>G1</color>\\n第3码头科芬公司临时总部","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"음? 이 번호는 미나 씨잖아……?","JPN":"うん？　この番号はミナさん……？","ENG":"Hmm? This number... it's Mina's.","TWN":"嗯？這個號碼是米娜的……？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"이런 시간에 어쩐 일이지?","JPN":"こんな時間にどうしたんだろう？","ENG":"What's she calling for at this hour?","TWN":"這麼晚了有什麼事嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어머, 미나 씨! 오랜만이네요!","JPN":"あら、ミナさん！　お久しぶりです！","ENG":"Oh! Mina! It's been a while!","TWN":"喔，米娜！好久不見了！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"오늘 퇴원한다고 들었는데, 이제 몸은 좀 괜찮으신가요?","JPN":"今日退院だと聞きましたけど、もう具合は大丈夫なんですか？","ENG":"I heard you were being discharged today. Feeling any better?","TWN":"聽說你今天出院，現在身體好些了嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"관리부장 님! 뭐 좀 물어볼 게 있어. 중요한 거야!","JPN":"管理部長！　ちょっと聞きたいことがある。大事なことなの！","ENG":"I have something to ask. It's important!","TWN":"管理部長！我有點事想問你，這事很重要！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네에? 중요하디니… 갑자기 무슨 일인가요?","JPN":"え？　大事なことって……急になんですか？","ENG":"Huh? Important...? What's going on all of a sudden?","TWN":"嗯？重要的事情……突然有什麼事嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"몇 달 전에 있었던 펜릴 소대 신입 사원 채용 공고 기억하지?","JPN":"数か月前にあった、フェンリル小隊の新入社員採用告知、覚えてる？","ENG":"Remember the Fenrir Squad recruitment posting from a few months back?","TWN":"還記得幾個月前芬里爾小隊新增員工的徵才公告嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그때, 지원자가 엄청 몰렸다가, 관리국 감사 때문에 다들 지원을 취소해 버렸잖아?","JPN":"あの時、最初は志願者が多かったけど、管理局の監査のせいでみんなキャンセルになったじゃない？","ENG":"There was a huge flood of applicants at first, but then everyone backed out after the Administration audit, right?","TWN":"那時候，申請者蜂擁而至，但因為管理局的審查，大家都取消了申請，不是嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아아, 네. 기억하죠.","JPN":"ああ、はい。覚えています。","ENG":"Ah, right. I remember.","TWN":"啊，是的，我記得。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그래서 결국 지원자는 한 명 밖에 남지 않았잖아요.","JPN":"それで、結局志願者は1人しか残りませんでしたよね。","ENG":"In the end, only one applicant remained.","TWN":"所以最後只剩下一個人來面試。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그, 그렇지……!?","JPN":"そ、そうだよね……！？","ENG":"R-right...?!","TWN":"是那、那樣嗎……？！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼, 그때 면접 봤던 녀석, 혹시 관리부장 님은 누구인지 기억해?","JPN":"じゃあ、あの時面接を受けた人が誰だったか、管理部長は覚えてる？","ENG":"So, do you happen to remember who that last interviewee was?","TWN":"那麼，那時候面試的傢伙，還記得管理部長是誰嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네? 그야 당연히 기억하긴 하지만…….","JPN":"え？　それはもちろん、覚えていますけど……","ENG":"Huh? Well, of course I remember, but...","TWN":"什麼？那當然記得……"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"누구였어!? 그 녀석의 이름을 말해 봐!!","JPN":"誰！？　そいつの名前言ってみて！！","ENG":"Then tell me! What was her name!?","TWN":"是誰？！說出那傢伙的名字！！！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"미나 씨, 갑자기 무슨 일 때문에 이러시는지 모르겠지만 일단 진정하세요.","JPN":"ミナさん、急にどうされたのかわかりませんが、とりあえず落ち着いてください。","ENG":"Mina, I don't know what's going on, but please calm down.","TWN":"米娜，不知道你突然這樣是為了什麼，但請先冷靜下來。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"미나 씨가 이렇게 흥분한 모습 처음 본다고요.","JPN":"こんなに取り乱しているミナさんは初めてです。","ENG":"I've never seen you so agitated before.","TWN":"我還是第一次看到米娜如此激動的樣子。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……아, 미안.","JPN":"……あ、ごめん。","ENG":"...Ah, sorry.","TWN":"……啊，抱歉。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"관리부장님한테는 갑작스러웠을지도 모르겠지만, 그래도 중요한 일이거든.","JPN":"突然すぎて困らせてしまったけど……でも大事なことなの。","ENG":"It might seem sudden to you, but this really is important.","TWN":"雖然對管理部長來說可能有些突然，但這確實是件重要的事。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"어쩌면 그 녀석, 좋지 못한 일에 휘말렸을지도 몰라서…….","JPN":"もしかしたらあいつ、何かよからぬことに巻き込まれてるのかもしれないし……","ENG":"She might have gotten caught up in something bad...","TWN":"或許那傢伙……可能捲入了不好的事情……"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네에? 그럼, 나이엘 씨에게 무슨 일이라도 생긴 건가요?","JPN":"え？　ということは、ナイエルさんに何かあったんですか？","ENG":"Huh? Wait, did something happen to Naielle?","TWN":"是嗎？那奈爾發生什麼事了嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"나이엘이라고……?","JPN":"ナイエル……？","ENG":"Did you say Naielle?","TWN":"奈爾……？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네? 지금 나이엘 씨 이야기하는 거 아니었나요?","JPN":"えっ？　今ナイエルさんの話をしていたのではなかったですか？","ENG":"Wait a second... aren't we talking about Naielle?","TWN":"是？現在不是在說奈爾的事嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};